$baseDir = "stitch_screens"
if (-not (Test-Path $baseDir)) {
    New-Item -ItemType Directory -Path $baseDir | Out-Null
}

foreach ($screen in $screens) {
    $dir = Join-Path $baseDir $screen.Name
    if (-not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir | Out-Null
    }
    
    $htmlPath = Join-Path $dir "index.html"
    $imgPath = Join-Path $dir "screenshot.png"
    
    Write-Host "Downloading $($screen.Name)..."
    curl.exe -L -o $htmlPath $screen.Html
    curl.exe -L -o $imgPath $screen.Img
}
Write-Host "Done downloading screens."
